code_walkthrough.code:
class Handler:
    def handle(self):
        print('Core logic')

class AuthMixin(Handler):
    def handle(self):
        print('Auth check')
        super().handle()

class CacheMixin(Handler):
    def handle(self):
        print('Cache check')
        super().handle()

class Endpoint(AuthMixin, CacheMixin):
    def handle(self):
        print('Endpoint hit')
        super().handle()

Endpoint().handle()

