class BaseMiddleware:
    def __init__(self):
        print('Base initialized')

class TracingMiddleware(BaseMiddleware):
    def __init__(self):
        print('Tracing initialized')
        super().__init__()

class MetricsMiddleware(BaseMiddleware):
    def __init__(self):
        print('Metrics initialized')
        super().__init__()

class ProductionMiddleware(TracingMiddleware, MetricsMiddleware):
    def __init__(self):
        print('Production initialized')
        super().__init__()

p = ProductionMiddleware()

